@app.route('/predict', methods=['POST'])
def predict_spam():
    try:
        data = request.get_json()
        
        if not data or 'email_text' not in data:
            return jsonify({
                'error': 'Missing email_text in request body'
            }), 400
        
        email_text = data['email_text']
        
        if not isinstance(email_text, str) or len(email_text.strip()) == 0:
            return jsonify({
                'error': 'email_text must be a non-empty string'
            }), 400
        
        email_vector = loaded_vectorizer.transform([email_text])
        
        spam_probability = loaded_model.predict_proba(email_vector)[0][1]
        
        prediction = 'spam' if spam_probability > 0.5 else 'ham'
        
        return jsonify({
            'email_text': email_text,
            'spam_probability': float(spam_probability),
            'ham_probability': float(1 - spam_probability),
            'prediction': prediction
        }), 200
    
    except Exception as e:
        return jsonify({
            'error': f'An error occurred: {str(e)}'
        }), 500

