@app.route('/train', methods=['POST'])
def retrain_model():
    try:
        data = request.get_json()
        
        if not data or 'emails' not in data or 'labels' not in data:
            return jsonify({
                'error': 'Missing emails or labels in request body'
            }), 400
        
        emails = data['emails']
        new_labels = data['labels']
        
        if len(emails) != len(new_labels):
            return jsonify({
                'error': 'Number of emails must match number of labels'
            }), 400
        
        global loaded_model, loaded_vectorizer
        
        new_vectorizer = CountVectorizer(max_features=500, stop_words='english', lowercase=True)
        X_new = new_vectorizer.fit_transform(emails)
        y_new = np.array(new_labels)
        
        new_model = LogisticRegression(max_iter=1000, random_state=42)
        new_model.fit(X_new, y_new)
        
        with open(MODEL_PATH, 'wb') as f:
            pickle.dump(new_model, f)
        
        with open(VECTORIZER_PATH, 'wb') as f:
            pickle.dump(new_vectorizer, f)
        
        loaded_model = new_model
        loaded_vectorizer = new_vectorizer
        
        return jsonify({
            'message': 'Model retrained successfully',
            'training_samples': len(emails)
        }), 200
    
    except Exception as e:
        return jsonify({
            'error': f'An error occurred during training: {str(e)}'
        }), 500

